\displaystyle{\begin{aligned}
   \frac{37}{45} - \frac{2}{9}
        \amp =  \frac{37}{45} - \frac{10}{45} \\
        \amp = \frac{37 - 10}{45} \\
        \amp = \frac{27}{45} \amp  \hbox{We can reduce this by dividing 9 into both the numerator and the denominator.
}\\
        \amp = \frac{3}{5}
\end{aligned}
    }
